// Rise 6.0 - AntiBot (tracks player list entries via S38):
if (packet instanceof S38PacketPlayerListItem) {
    S38PacketPlayerListItem s38 = (S38PacketPlayerListItem) packet;

    for (S38PacketPlayerListItem.AddPlayerData data : s38.getEntries()) {
        switch (s38.getAction()) {
            case ADD_PLAYER:
                // Add UUID to valid player set
                validPlayers.add(data.getProfile().getId());
                // Track name for NameProtect
                playerNames.put(data.getProfile().getId(), data.getProfile().getName());
                break;
            case REMOVE_PLAYER:
                validPlayers.remove(data.getProfile().getId());
                playerNames.remove(data.getProfile().getId());
                break;
            case UPDATE_LATENCY:
                // Real players get ping updates — bots don't
                // If an entity hasn't received a ping update in 10s, it might be a bot
                lastPingUpdate.put(data.getProfile().getId(), System.currentTimeMillis());
                break;
        }
    }
}

// Then in KillAura target selection:
Entity target = findBestTarget();
if (target instanceof EntityPlayer) {
    EntityPlayer player = (EntityPlayer) target;
    if (!validPlayers.contains(player.getUniqueID())) {
        // This player has no tab list entry — probably a bot
        return; // skip this target
    }
    // Check if this player has received recent ping updates
    if (System.currentTimeMillis() - lastPingUpdate.getOrDefault(player.getUniqueID(), 0L) > 10000) {
        // No ping update in 10 seconds — suspicious
        return;
    }
}

// Vanilla S38PacketPlayerListItem definition:
package net.minecraft.network.play.server;

public class S38PacketPlayerListItem implements Packet<INetHandlerPlayClient> {
    private Action action;
    private List<AddPlayerData> players;

    public enum Action {
        ADD_PLAYER, UPDATE_GAMEMODE, UPDATE_LATENCY,
        UPDATE_DISPLAY_NAME, REMOVE_PLAYER
    }

    public class AddPlayerData {
        private final int ping;
        private final WorldSettings.GameType gamemode;
        private final GameProfile profile;
        private final IChatComponent displayName;

        public AddPlayerData(GameProfile profile, int pingIn,
                             WorldSettings.GameType gamemodeIn, IChatComponent displayNameIn) {
            this.profile = profile;
            this.ping = pingIn;
            this.gamemode = gamemodeIn;
            this.displayName = displayNameIn;
        }

        public GameProfile getProfile() { return this.profile; }
        public int getPing() { return this.ping; }
        public WorldSettings.GameType getGameMode() { return this.gamemode; }
        public IChatComponent getDisplayName() { return this.displayName; }
    }

    public Action getAction() { return this.action; }
    public List<AddPlayerData> getEntries() { return this.players; }
}

