// Aqua 13 - SessionInfo reads S38 for player count:
if (packet instanceof S38PacketPlayerListItem) {
    S38PacketPlayerListItem s38 = (S38PacketPlayerListItem) packet;
    if (s38.getAction() == Action.ADD_PLAYER) {
        onlinePlayers += s38.getEntries().size();
    } else if (s38.getAction() == Action.REMOVE_PLAYER) {
        onlinePlayers -= s38.getEntries().size();
    }
}

